#include <vector>
#include <queue>
#include <tuple>
#include <climits>

using namespace std;

long long solve(long long m, long long n, vector<vector<long long>> waitCost) {
    // Directions: right (0, 1), down (1, 0)
    const int dirs[2][2] = {{0, 1}, {1, 0}};

    // Priority queue: (total_cost, i, j, step)
    priority_queue<tuple<long long, long long, long long, long long>, 
                   vector<tuple<long long, long long, long long, long long>>,
                   greater<tuple<long long, long long, long long, long long>>> pq;

    // Distance matrix: dist[i][j][step % 2] = min cost to reach (i,j) at step
    vector<vector<vector<long long>>> dist(m, vector<vector<long long>>(n, vector<long long>(2, LLONG_MAX)));

    // Initial position (0, 0) at step 1
    long long initial_cost = (0 + 1) * (0 + 1);
    pq.emplace(initial_cost, 0, 0, 1);
    dist[0][0][1 % 2] = initial_cost;

    while (!pq.empty()) {
        auto [current_cost, i, j, step] = pq.top();
        pq.pop();

        if (i == m - 1 && j == n - 1) {
            return current_cost;
        }

        if (step % 2 == 1) {
            // Odd step: move right or down
            for (auto& dir : dirs) {
                long long ni = i + dir[0];
                long long nj = j + dir[1];
                if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                    long long move_cost = (ni + 1) * (nj + 1);
                    long long new_cost = current_cost + move_cost;
                    long long new_step = step + 1;
                    if (new_cost < dist[ni][nj][new_step % 2]) {
                        dist[ni][nj][new_step % 2] = new_cost;
                        pq.emplace(new_cost, ni, nj, new_step);
                    }
                }
            }
        } else {
            // Even step: wait
            long long wait_cost = waitCost[i][j];
            long long new_cost = current_cost + wait_cost;
            long long new_step = step + 1;
            if (new_cost < dist[i][j][new_step % 2]) {
                dist[i][j][new_step % 2] = new_cost;
                pq.emplace(new_cost, i, j, new_step);
            }
        }
    }

    return -1; // Should not reach here if path exists
}

